console.log("INPUT COUNT:", $input.all().length);

for (const item of $input.all()) {
  // Aceita texto em várias chaves possíveis
  const rawOutput = item.json.output ?? item.json.text ?? item.json.response ?? item.json.texto ?? item.json;

  let aiData;

  try {
    // Se rawOutput for string JSON, tenta parsear; se for objeto, usa direto
    if (typeof rawOutput === 'string') {
      // tenta parsear, mas se falhar, cai no catch e montamos fallback
      aiData = JSON.parse(rawOutput);
    } else {
      aiData = rawOutput;
    }
  } catch (err) {
    // fallback: se for uma string simples ou outro formato
    aiData = { texto: String(rawOutput ?? ''), adicionais: {} };
  }

  // Se o campo texto for um array (ex: IA já devolveu array de parágrafos), trata
