let delay;
if (r < 0.66) {
  delay = 9 + Math.random() * (15 - 9);
} else {
  delay = 15 + Math.random() * (30 - 15);
}

// Retorna corretamente para o n8n
return [
  {
    json: {
      delaySegundos: delay
    }
  }
];

